import{_ as t,o as a,c as o,ak as r,aE as i}from"./chunks/framework.B5fSzMAO.js";const m=JSON.parse('{"title":"Introduction","description":"","frontmatter":{},"headers":[],"relativePath":"dotpi-box/introduction.md","filePath":"dotpi-box/introduction.md"}'),n={name:"dotpi-box/introduction.md"};function s(d,e,l,h,c,u){return a(),o("div",null,[...e[0]||(e[0]=[r('<h1 id="introduction" tabindex="-1">Introduction <a class="header-anchor" href="#introduction" aria-label="Permalink to “Introduction”">​</a></h1><p>Thanks to the <a href="https://soundworks.dev/" target="_blank" rel="noreferrer"><em>soundworks</em></a> JavaScript framework and the <em>dotpi-tools</em> developed during the DOTS research program, one can easily control a fleet of nano-computers over the network (i.e. Raspberry Pi). Powered by external power banks and equipped with amplifiers, these objects turn into distributed autonomous speakers. Moreover, thanks to the <a href="https://github.com/ircam-ismm/node-web-audio-api" target="_blank" rel="noreferrer"><em>node-web-audio-api</em></a> these objects are able to compute and synthesize sound controlled in real-time through the network in a straightforward workflow using web technologies.</p><p><img src="'+i+'" alt="the-box"></p><h2 id="why" tabindex="-1">Why <a class="header-anchor" href="#why" aria-label="Permalink to “Why”">​</a></h2><p>From a software point of view, we therefore have access to all the required technologies to build a distributed audio system.</p><p>Some of the benefits of such systems include portability, ease of deployment and optimization among other things. From this point of view, it is not desirable to have all the necessary equipment broken down into many different parts which would lead into a tedious process of setting up and operating the system.</p><p>This tutorial aims to guide you into building speakers adapted to distributed musical systems.</p><h2 id="related-documentation-an-tutorials" tabindex="-1">Related documentation an tutorials <a class="header-anchor" href="#related-documentation-an-tutorials" aria-label="Permalink to “Related documentation an tutorials”">​</a></h2><h3 id="soundworks" tabindex="-1"><em>soundworks</em> <a class="header-anchor" href="#soundworks" aria-label="Permalink to “soundworks”">​</a></h3><p>Open-source creative coding framework for distributed applications based on Web technologies.</p><ul><li><a href="https://soundworks.dev/tutorials/getting-started.html" target="_blank" rel="noreferrer">Tutorials</a></li><li><a href="https://soundworks.dev/soundworks/" target="_blank" rel="noreferrer">Documentation</a></li></ul><h3 id="web-audio-api" tabindex="-1">Web Audio API <a class="header-anchor" href="#web-audio-api" aria-label="Permalink to “Web Audio API”">​</a></h3><p>A powerful and versatile system for controlling audio on the Web, allowing developers to choose audio sources, add effects to audio, create audio visualizations, apply spatial effects (such as panning) and much more.</p><ul><li><a href="https://ircam-ismm.github.io/webaudio-tutorials/" target="_blank" rel="noreferrer">Tutorials</a></li><li><a href="https://developer.mozilla.org/en-US/docs/Web/API/Web_Audio_API" target="_blank" rel="noreferrer">Documentation</a></li><li><a href="https://github.com/ircam-ismm/node-web-audio-api/" target="_blank" rel="noreferrer">node-web-audio-api GitHub</a></li></ul><h3 id="dotpi-ecosystem" tabindex="-1">dotpi ecosystem <a class="header-anchor" href="#dotpi-ecosystem" aria-label="Permalink to “dotpi ecosystem”">​</a></h3><p>The <em>dotpi</em> ecosystem aims at facilitating the creation and maintenance of a fleet of Raspberry Pi nano-computers to run distributed audio applications.</p><ul><li><a href="https://ircam-ismm.github.io/dotpi/" target="_blank" rel="noreferrer">Tutorials</a></li></ul><h3 id="alternatives" tabindex="-1">Alternatives <a class="header-anchor" href="#alternatives" aria-label="Permalink to “Alternatives”">​</a></h3><p>Such systems have already been explored and developed, such as the <a href="https://univ-cotedazur.fr/recherche-innovation/structures-de-recherche/academies-dexcellence/academie-dexcellence-homme-idees-et-milieux/projets-de-recherche/projets-2020-2024/presence-electroacoustique-pre%CC%81" target="_blank" rel="noreferrer">PrÉ devices</a> for example</p>',19)])])}const b=t(n,[["render",s]]);export{m as __pageData,b as default};
